document.addEventListener('DOMContentLoaded', () => { const isLookbook = document.body.classList.contains('lookbook-page'); if (!isLookbook) return; const revealElements = [...document.querySelectorAll('[data-reveal]')].filter( el => !el.closest('.site-footer') ); const revealObserver = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) { entry.target.classList.add('revealed'); revealObserver.unobserve(entry.target); } }); }, { threshold: 0.08, rootMargin: '0px 0px -40px 0px' }); revealElements.forEach(el => revealObserver.observe(el)); const lazyVideos = document.querySelectorAll('.lb-video'); if ('IntersectionObserver' in window) { const videoObserver = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) { const video = entry.target; const source = video.querySelector('source'); if (source && !source.dataset.loaded) { video.load(); source.dataset.loaded = 'true'; } video.play().catch(() => {}); videoObserver.unobserve(video); } }); }, { threshold: 0.2 }); lazyVideos.forEach(video => videoObserver.observe(video)); } const hero = document.querySelector('.lb-hero'); const heroImage = document.querySelector('.lb-hero-image'); if (hero && heroImage) { const handleParallax = () => { const scrollY = window.scrollY; const heroHeight = hero.offsetHeight; if (scrollY <= heroHeight) { const progress = scrollY / heroHeight; heroImage.style.transform = `translateY(${progress * 20}px) scale(${1 + progress * 0.02})`; } }; window.addEventListener('scroll', handleParallax, { passive: true }); handleParallax(); }
});